+}
+
+// ── MicroLoRA ────────────────────────────────────────────────
+
+/**
+ * Create a MicroLoRA adapter (ultra-lightweight LoRA, ranks 1-4).
+ * v2.0.2: .adapt(input, feedback) takes Float32Array + AdaptFeedbackWasm.
+ */
+export async function createMicroLora(config: MicroLoraConfig): Promise<{
