+  adapt: (quality: number, learningRate?: number, success?: boolean) => void;
+  applyUpdates: (gradients: Float32Array) => void;
+  stats: () => string;
+  reset: () => void;
+  toJson: () => string;
+  pendingUpdates: () => number;
+}> {
